412		if err != nil {
413			return fmt.Errorf("agent: list harnesses: %w", err)
414		}
415		found := false
416		for _, info := range infos {
417			if info.Name == harnessName {
418				found = true
419				if !info.Available {
420					return fmt.Errorf("agent: harness %s not available", harnessName)
421				}
422				break
423			}
424		}
425		if !found {
426			return fmt.Errorf("agent: unknown harness: %s", harnessName)
427		}
